#include<bits/stdc++.h>
#define LL long long
#define fr first
#define se second
#define pb push_back
using namespace std;
const int N = 1e5+5 , K = (1<<18)+5;
int c,n,a[N],dis[K];queue<pair<int,int>> q;
int main(){
    //freopen("field.in","r",stdin);
    //freopen("field.out","w",stdout);
    cin>>c>>n;
    for(int i=1;i<=n;i++)for(int j=0;j<c;j++)
        {char ch;cin>>ch;if(ch=='G')a[i]|=(1<<j);}
    memset(dis,-1,sizeof(dis));
    for(int i=1;i<=n;i++)dis[a[i]]=0,q.push({a[i],0});
    while(!q.empty()){
        auto [u,d]=q.front();q.pop();
        for(int i=0;i<c;i++){
            int v=u^(1<<i);
            if(dis[v]==-1)dis[v]=d+1,q.push({v,dis[v]});
        }
    }
    for(int i=1;i<=n;i++)cout<<c-dis[(1<<c)-1-a[i]]<<"\n";
    return 0;
}
